@startuml
title Class Diagram Title

interface IFoo {
  + void method(); // public
}

class Bar {
  + static String name;
  + Foo foo;
  # int x; // protected
  ~ int y; // default
  - void method(String string); // private
}

class Foo {
  + int x;
  + void methodA();
}

class Qoo {
  + Foo foo;
}

note right of Foo
  public : +
  protected : #
  default : ~
  private : -
  Foo는 Bar가 Aggregation한다.(Bar -o Foo)
  Foo는 Qoo가 Composition한다.(Qoo -* Foo)
  Foo는 IFoo를 상속한다.(Foo -|> IFoo)
end note

note bottom of Bar
  void method(String string){
    return string;
  }
end note

Bar -[hidden]-> IFoo
Bar -[hidden]-> Foo
Bar -[hidden]-> Qoo
Bar -[hidden]-> note
Foo -[hidden]-> note

Bar -|> IFoo
Bar o-- Foo
Qoo *-- Foo
Foo -|> IFoo

@enduml
